#!/bin/sh
set -eu

for f in /app/client/dist/index.html /app/client/index.html; do
  if [ -f "$f" ]; then
    sed -i 's|<title>LibreChat</title>|<title>AI Total Rank</title>|g' "$f"
    sed -i 's|content="LibreChat - An open source chat application with support for multiple AI models"|content="AI Total Rank - AI workspace for SEO, ranking, and AI workflows"|g' "$f"
  fi
done

cat > /app/client/dist/assets/favicon-32x32.png.b64 <<'EOF'

EOF
base64 -d /app/client/dist/assets/favicon-32x32.png.b64 > /app/client/dist/assets/favicon-32x32.png
rm -f /app/client/dist/assets/favicon-32x32.png.b64

cat > /app/client/dist/assets/favicon-16x16.png.b64 <<'EOF'

EOF
base64 -d /app/client/dist/assets/favicon-16x16.png.b64 > /app/client/dist/assets/favicon-16x16.png
rm -f /app/client/dist/assets/favicon-16x16.png.b64

cat > /app/client/dist/assets/apple-touch-icon-180x180.png.b64 <<'EOF'

EOF
base64 -d /app/client/dist/assets/apple-touch-icon-180x180.png.b64 > /app/client/dist/assets/apple-touch-icon-180x180.png
rm -f /app/client/dist/assets/apple-touch-icon-180x180.png.b64
